const parsed = $('Parse Agent1').first().json;
const cal = parsed.calendar_event_to_save || {};
const note = parsed.chat_note_to_save || {};
const senderId = String(parsed.senderId || '');
const caseFile = parsed.case_file || 'Unknown';

const results = [];

if (cal.title && cal.title.trim() !== '') {
    results.push({ json: {
          type: 'calendar_event',
          title: cal.title.trim(),
          description: cal.description || null,
          start_at: cal.start_at || null,
          end_at: cal.end_at || null,
          location: cal.location || null,
          related_tct: cal.related_tct || null,
          related_case: cal.related_case || caseFile,
          client_name: cal.client_name || null,
          created_by_telegram_id: senderId
    }});
}

if (note.content && note.content.trim() !== '') {
    results.push({ json: {
          type: 'chat_note',
          content: note.content.trim(),
          summary: note.summary || null,
          topic: note.topic || null,
          importance: note.importance || 1,
          related_tct: note.related_tct || null,
          related_case: note.related_case || caseFile,
          client_name: note.client_name || null,
          created_by_telegram_id: senderId
    }});
}

if (results.length === 0) {
    return [{ json: { skip: true } }];
}

return results;
